#include <stdlib.h>

typedef struct node { int val; struct node *next; } node_t;

void remove_node(node_t *head, int target) {
    node_t *prev = NULL, *cur = head;
    while (cur) {
        if (cur->val == target) {
            if (prev) prev->next = cur->next;
            free(cur);
        }
        prev = cur;
        cur = cur->next;  /* FLAW: cur already freed */
    }
}

#include <stdlib.h>

typedef struct node { int val; struct node *next; } node_t;

void remove_node_safe(node_t *head, int target) {
    node_t *prev = NULL, *cur = head;
    while (cur) {
        node_t *next = cur->next;  /* FIX: save next before free */
        if (cur->val == target) {
            if (prev) prev->next = next;
            free(cur);
        } else {
            prev = cur;
        }
        cur = next;
    }
}

