#include <string.h>

void parse_header(const char *raw) {
    char name[32], value[128];
    /* FLAW: sscanf with no width limit */
    sscanf(raw, "%s: %s", name, value);
    store_header(name, value);
}

#include <string.h>

void parse_header_safe(const char *raw) {
    char name[32], value[128];
    /* FIX: width specifiers */
    sscanf(raw, "%31s: %127s", name, value);
    store_header(name, value);
}

#include <stdlib.h>

typedef struct event { int type; void (*handler)(void*); void *data; } event_t;

void dispatch_event(event_t *ev) {
    ev->handler(ev->data);
    free(ev);
    /* FLAW: ev->type read after free */
    log_event(ev->type);
}

#include <stdlib.h>

typedef struct event { int type; void (*handler)(void*); void *data; } event_t;

void dispatch_event_safe(event_t *ev) {
    int type = ev->type;  /* FIX: save before free */
    ev->handler(ev->data);
    free(ev);
    log_event(type);
}
